static const uint16_t* const OUTFITS[] = {
  OUTFIT_0, OUTFIT_1, OUTFIT_2, OUTFIT_3, OUTFIT_4, OUTFIT_5
};

// Returns outfit index (0-5) for a temperature in Fahrenheit
static inline uint8_t outfit_index(float tempF) {
  if (tempF >= 78.8f) return 0;
  if (tempF >= 69.8f) return 1;
  if (tempF >= 59.0f) return 2;
  if (tempF >= 50.0f) return 3;
  if (tempF >= 39.2f) return 4;
  return 5;
}

// Draw the correct outfit for a temperature (Fahrenheit)
// bgColor: RGB565 background color (default black 0x0000)
// Call after canvas_begin().
static inline void draw_outfit_for_temp(Arduino_GFX* gfx, float tempF, int16_t x = 0, int16_t y = 0) {
  uint8_t idx = outfit_index(tempF);
  gfx->draw16bitRGBBitmapWithTranColor(x, y, (uint16_t*)pgm_read_ptr(&OUTFITS[idx]), OUTFIT_TRANSPARENT, OUTFIT_W, OUTFIT_H);
}
